func (s *Store) SearchRoles(query string, limit int) ([]json.RawMessage, error) {
	if limit <= 0 {
		limit = 50
	}
	matchQuery := ftsMatchQuery(query)
	if matchQuery == "" {
		return nil, nil
	}
	rows, err := s.db.Query(
		`SELECT t.data FROM "roles" t
		 JOIN "roles_fts" ON "roles_fts".rowid = t.rowid
		 WHERE "roles_fts" MATCH ?
		 ORDER BY rank LIMIT ?`,
		matchQuery, limit,
	)
	if err != nil {
		return nil, err
	}
	defer rows.Close()

	var results []json.RawMessage
	for rows.Next() {
		var data string
		if err := rows.Scan(&data); err != nil {
			return nil, err
		}
		results = append(results, json.RawMessage(data))
	}
	return results, rows.Err()
}

